{
    if (m_memoryHotpatch) {
        connect(m_memoryHotpatch.get(), &ModelMemoryHotpatch::errorOccurred,
                this, [this](const PatchResult& pr) {
                    emit errorOccurred(patchResultToUnified(pr, "MemoryError"));
